<?php
namespace Tests\Feature;
use App\Domain\Characters\Accounts\ActiveCharacterContext;use App\Models\Character;use App\Models\User;use Database\Seeders\CharacterLevelRequirementSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class CharacterSelectionTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(CharacterLevelRequirementSeeder::class);}public function test_selector_lists_only_own_three_slots_and_marks_current(){$user=User::factory()->create();$a=Character::factory()->for($user)->create(['name'=>'Alpha']);$b=Character::factory()->for($user)->create(['name'=>'Beta']);Character::factory()->create(['name'=>'Foreign']);app(ActiveCharacterContext::class)->select($user,$b);$response=$this->actingAs($user)->get(route('characters.select'))->assertOk()->assertSee('Alpha')->assertSee('Beta')->assertDontSee('Foreign')->assertSee('Seleccionado actualmente');$this->assertSame(3,substr_count($response->getContent(),'class="card hero-slot'));}public function test_selection_is_idempotent_and_foreign_is_forbidden(){$user=User::factory()->create();$character=Character::factory()->for($user)->create();$foreign=Character::factory()->create();$this->actingAs($user)->post(route('characters.select.store',$character))->assertRedirect(route('dashboard'));$this->post(route('characters.select.store',$character))->assertRedirect(route('dashboard'));$this->assertSame($character->id,$user->fresh()->active_character_id);$this->post(route('characters.select.store',$foreign))->assertForbidden();}public function test_login_always_enters_selector_when_account_has_character(){$user=User::factory()->create(['password'=>bcrypt('secret123')]);Character::factory()->selectedFor($user)->create();$this->post('/login',['email'=>$user->email,'password'=>'secret123'])->assertRedirect(route('characters.select'));}}
